function benchmark(input) {
  return Object.freeze({
    id: input.id,
    command: input.command,
    explicitCommand: input.explicitCommand,
    scope: input.scope,
    source: input.source,
    docs: input.docs,
    fixtureProfiles: Object.freeze(input.fixtureProfiles.map(profile => Object.freeze(profile))),
    defaultFixtureProfile: input.defaultFixtureProfile,
    env: Object.freeze(input.env),
    runtimeIsolation: input.runtimeIsolation,
    tmuxMode: input.tmuxMode,
    warmupIterations: input.warmupIterations,
    measuredIterations: input.measuredIterations,
    expectedOutputFields: Object.freeze(input.expectedOutputFields),
    metadataFields: Object.freeze(input.metadataFields),
    leakGuard: Object.freeze(input.leakGuard),
    baselineOnly: true,
    futureGate: true,
    futureGateOwner: FUTURE_GATE_OWNER,
    releaseReadyClaim: false,
    nonGoals: COMMON_NON_GOALS,
  })
}

